var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으아아, 위험했다.","JPN":"うあぁ、危なかった。","ENG":"Whoa, that was close.","TWN":"唉，好險。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"무턱대고 바이크 흔적만 쫓다가 벌써 죽을 고비를 몇 번이나 넘긴 거야.","JPN":"がむしゃらにバイクの後を追ったせいで、何回も死にかけたよ。","ENG":"I don't know how many times I almost died by blindly chasing the bike tracks.","TWN":"盲目追隨摩托車胎痕已經讓我幾次險些喪命。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런 엄청난 일을 다 겪고 나서도, 장비 도움이 없으면 실력은 예전이랑 똑같구나.","JPN":"あんな凄いことを経験したのに、装備の助けが無ければ、実力は昔のままなんだよな。","ENG":"I guess, even after all I've been through, I'm the same without the help of my gear.","TWN":"明明經歷了這麼多，我的實力如果沒有裝備加持仍然沒什麼改變。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"솔직히 지금도… 번쩍하고 누가 날 도와주러 오는 상상이나 하고 있잖아.","JPN":"正直今も……誰かがパッと現れて、助けてくれることを想像してたりして。","ENG":"Even now... I'm just waiting for someone to randomly appear and save me.","TWN":"老實說，即使是現在……我還在幻想著有人突然冒出來救我。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"호라이즌 씨라거나… 노르드나빅의 군인분들이나… 아니면 하늘을 나는 엄청나게 센 호라이즌 씨…","JPN":"ホライズンさんとか……ノルドナビックの軍人さんとか……それとも空を飛ぶめっちゃ強いホライズンさん……","ENG":"Maybe someone like Horizon... or the Nordnavik soldiers... or maybe the super strong version of flying Horizon...","TWN":"比如地平線……或者是諾爾德萊比的士兵……或者是在天上飛的超強地平線……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그렇게 도망쳐 놓고서 또 기적을 바라다니. 나도 참 염치가 없지.","JPN":"あんなに逃げ回ってそれでも奇跡を願うとは。私ってバカだな。","ENG":"Can't believe I'm hoping for a miracle again after all those times I ran away. Didn't know I was that shameless.","TWN":"只顧逃跑還渴望奇蹟，我真是不要臉。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하지만 그렇다곤 해도…","JPN":"でも、そうだったとしても……","ENG":"But even so...","TWN":"但即便如此……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…이번엔 이상하게, 도망치고 싶은 마음은 들지 않아.","JPN":"……なぜか今は、逃げたいと思わない。","ENG":"...It feels different this time. I don't want to make a run for it.","TWN":"……這次我卻不想逃跑了，好奇怪。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"윽! 저리 좀 가!!","JPN":"うっ！　あっち行って！！","ENG":"Ngh! Go away!!","TWN":"呃！離我遠點！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아까보다 침식체가 많아. 점점 가까워지고 있어.","JPN":"さっきより侵食体が多い。どんどん近づいてる。","ENG":"There are more C.O.s than before. I must be getting close.","TWN":"這裡的侵蝕體比剛才還多，還越來越靠近。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…무사해야 돼요.","JPN":"……どうか無事でありますように。","ENG":"...Please, be safe.","TWN":"……希望平安無事。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"여기도 침식체가 있다고?","JPN":"ここにも侵食体がいるって？","ENG":"C.O.s are here as well?","TWN":"這裡也有侵蝕體？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"빠져나갈 틈 없이 포위당했어.","JPN":"囲まれて逃げる隙がない。","ENG":"I'm completely surrounded.","TWN":"我被徹底包圍了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"큭?!","JPN":"くっ！？","ENG":"Kgh?!","TWN":"咳？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"…찾았다.","JPN":"……見ツケタ。","ENG":"...Found you.","TWN":"……找到了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이쯤 퇴짜를 놨으면 알아서 꺼져줬으면 하는데.","JPN":"これだけ突っぱねられたら、察して消えてほしいんだけど。","ENG":"Can't you take a hint and leave me alone?","TWN":"你差不多該放棄了吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"사람말만 배우고 눈치가 영 꽝이네.","JPN":"人の言葉を習ったくせに、空気は読めないんだ。","ENG":"You might speak our language, but you can't seem to read the room.","TWN":"你只學會了人類的語言，沒學到觀察力。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"커헉…!","JPN":"ぐはっ……！","ENG":"Kuh...!","TWN":"咳嚇……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_WATER"},{"id":"L37_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"나약한 포식자…","JPN":"軟弱ナ捕食者……","ENG":"Weak predator...","TWN":"羸弱的捕食者……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"네 힘은… 우리 거다.","JPN":"オマエノ力ハ……我々ノモノダ。","ENG":"Your strength... is ours.","TWN":"你的力量是……我們的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭐야, 이게.","JPN":"なに、これ。","ENG":"What is this?","TWN":"搞什麼鬼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 아는 마에스트로라면 이런 녀석에게 지진 않았을 텐데…","JPN":"私が知っているマエストロならこんなやつに負けたりはしないはずなのに……","ENG":"The Maestra I know wouldn't lose to something like this...","TWN":"我所認識的指揮家可不會輸給這種傢伙……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"평범하게 감정을 갖고… 평범하게 약한 인간이 됐으니까… 이런 식으로 죽는 건가…?","JPN":"普通に感情を持ち……普通の弱い人間になったから……こんなふうに死んでしまうのか……？","ENG":"Am I dying like this because... I've become a normal, weak human... with normal emotions...?","TWN":"變成了平凡的人類……擁有了平凡的感情……所以會迎來這樣的死亡嗎……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"아니.","JPN":"いや。","ENG":"No.","TWN":"不。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"언제까지 기억 타령이나 하며 그늘에 갇혀 있을 셈인 건데.","JPN":"いつまで記憶に苦しめられて自分の殻に閉じこもっているつもりなんだ。","ENG":"How much longer are you going to whine about your memories and stay trapped in the shadows?","TWN":"究竟還要在記憶的陰影中困多久。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"크리스가 구한 건 마에스트로가 아니라 너야. 레아 슈나이더.","JPN":"クリスが助けたのはマエストロじゃない、君だ。レア・シュナイダー。","ENG":"Chris saved you, not Maestra. Leah Schneider.","TWN":"克莉絲拯救的不是指揮家，而是你，蕾亞·修奈德。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"적어도… 네가 그 괴물과 다르다는 걸 증명하기 전까지…","JPN":"少なくとも……君がその化け物とは違うということを証明するまでは……","ENG":"At least... until you prove that you are different from that monster...","TWN":"至少……在你證明自己和那個怪物不同之前……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"…넌 죽을 자격이 없어.","JPN":"……君に死ぬ資格なんかない。","ENG":"...You have no right to die.","TWN":"……你沒資格死去。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"방금 저 빛은 뭐지?","JPN":"今の光はなんだ？","ENG":"What was that light?","TWN":"剛剛那道光是？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};